package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	User    string
	Message string
}

var comments = []Comment{
	{User: "Alice", Message: "This is a <b>bold</b> comment."},
	{User: "Bob", Message: "Here's a comment with <i>italics</i>."},
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	const tpl = `
	<!DOCTYPE html>
	<html>
	<head>
		<title>User Comments</title>
	</head>
	<body>
	<h1>Comments</h1>
	<ul>
		{{range .}}
			<li>
				<strong>{{.User}}:</strong> <span>{{.Message}}</span>
			</li>
		{{end}}
	</ul>
	</body>
	</html>
	`

	t := template.Must(template.New("comments").Parse(tpl))
	t.Execute(w, comments)
}

func main() {
	http.HandleFunc("/comments", commentsHandler)
	http.ListenAndServe(":8080", nil)
}